using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so we must opt back in.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 uses only the raw key for "id" (e.g. "1").
            // Existing documents have "id" = "Blog|1", so preserve that format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: EF 9 removed support for HasIndex on Cosmos.
            // Cosmos has no secondary-index support in EF; remove the call.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

