class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF 9 renamed the discriminator property from
        // "Discriminator" to "$type". Any raw SQL that filters on the old
        // property name must be updated, OR keep using "Discriminator" via
        // HasDiscriminator (as done in BlogContext). Since we opted to keep
        // "Discriminator", existing SQL continues to work unchanged.
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

